const express = require('express');
const app = express();
const http = require('http').createServer(app);
const io = require('socket.io')(http);
const playerDB = {};

app.use(express.static('public'));

io.on('connection', (socket) => {
  console.log(`A new client connected: ${socket.id}`);

  socket.on('join', (data) => {
    const username = data.username;
    const score = data.score;
    if (!playerDB[username]) {
      playerDB[username] = {};
    }
    playerDB[username].socketId = socket.id;
    playerDB[username].score = score;
    console.log(`Client ${socket.id} joined as ${username} with a score of ${score}`);
  });

  socket.on('disconnect', () => {
    const username = getUsername(socket.id);
    delete playerDB[username];
    console.log(`Client ${socket.id} disconnected`);
  });

  socket.on('move', (data) => {
    // Validate move on client side
    if (!isValidMove(data)) {
      console.log(`Invalid move from client ${socket.id}`);
      return;
    }
    const username = getUsername(socket.id);
    playerDB[username].score++;
    io.sockets.emit('update', { username, score: playerDB[username].score });
  });
});

function isValidMove(data) {
  // Validate move logic here
}

function getUsername(socketId) {
  return Object.keys(playerDB).find((username) => playerDB[username].socketId === socketId);
}